import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { PlaybookModule, UserRole, SolutionItem, SolutionCategory, SolutionMaturity, ProposalItem } from '../types';
import { SupabaseService } from '../services/api';
import AdminSettings from './AdminSettings';
import SalesDashboard from './SalesDashboard';
import Fichario from './Fichario';
import ProposalSimulator from './ProposalSimulator';
import NossaEssencia from './NossaEssencia';
import PlaybookGuide from './PlaybookGuide';
import SLAPage from './SLAPage';

interface PlaybookEditorProps {
  module: PlaybookModule;
  currentRole: UserRole;
  onNavigateToModule?: (id: string) => void;
}

const PlaybookEditor: React.FC<PlaybookEditorProps> = ({ module, currentRole, onNavigateToModule }) => {
  const [selectedSolution, setSelectedSolution] = useState<SolutionItem | null>(null);
  const [catalogData, setCatalogData] = useState<SolutionItem[]>([]);
  const [selectedOptions, setSelectedOptions] = useState<Record<string | number, string[]>>({});
  const [addingToProposal, setAddingToProposal] = useState<string | number | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [activeSubcategory, setActiveSubcategory] = useState<string>('Todos');
  const [proposalCount, setProposalCount] = useState(0);

  // Inicializa o contador da proposta
  useEffect(() => {
    const currentProposal = JSON.parse(localStorage.getItem('phant_current_proposal') || '[]');
    setProposalCount(currentProposal.length);
  }, []);

  const loadData = useCallback(async () => {
    if (module.id !== 'catalogo') return;
    setIsLoading(true);
    const saved = localStorage.getItem('phant_catalog_data');
    if (saved) setCatalogData(JSON.parse(saved));

    try {
      const cloudData = await SupabaseService.fetchSolutions();
      if (cloudData && cloudData.length > 0) {
        setCatalogData(cloudData);
        localStorage.setItem('phant_catalog_data', JSON.stringify(cloudData));
      }
    } catch (err) {
      console.error("Sync error:", err);
    } finally {
      setIsLoading(false);
    }
  }, [module.id]);

  useEffect(() => { loadData(); }, [loadData]);

  const getCategoryMeta = (cat: SolutionCategory) => {
    switch (cat) {
      case 'Direção': return { bg: 'bg-[#00B884]', text: 'text-[#00B884]', light: 'bg-[#00B884]/10' };
      case 'Propagação': return { bg: 'bg-[#0095FF]', text: 'text-[#0095FF]', light: 'bg-[#0095FF]/10' };
      case 'Aceleração': return { bg: 'bg-[#7C3AED]', text: 'text-[#7C3AED]', light: 'bg-[#7C3AED]/10' };
      default: return { bg: 'bg-gray-900', text: 'text-gray-900', light: 'bg-gray-100' };
    }
  };

  const processedData = useMemo(() => {
    const maturityOrder: Record<SolutionMaturity, number> = { 'Base': 1, 'Pro': 2, 'Advanced': 3 };
    let filtered = [...catalogData];
    if (activeSubcategory !== 'Todos') {
      filtered = filtered.filter(item => item.subcategoria === activeSubcategory || item.subcategoria.includes(activeSubcategory));
    }
    return filtered.sort((a, b) => (maturityOrder[a.maturidade] || 99) - (maturityOrder[b.maturidade] || 99));
  }, [catalogData, activeSubcategory]);

  const addToProposal = (item: SolutionItem) => {
    setAddingToProposal(item.id);
    const activeLabels = selectedOptions[item.id] || [];
    const chosenOptions = (item.variaveis_opcionais || []).filter(opt => activeLabels.includes(opt.label));
    const totalPrice = (item.valor_base_num || 0) + chosenOptions.reduce((acc, curr) => acc + curr.valor, 0);

    const proposalItem: ProposalItem = {
      instanceId: `${item.id}-${Date.now()}`,
      solutionId: item.id,
      name: item.solucao,
      basePrice: item.valor_base_num || 0,
      selectedOptions: chosenOptions,
      totalPrice: totalPrice,
      duration: item.duracao
    };

    const currentProposal = JSON.parse(localStorage.getItem('phant_current_proposal') || '[]');
    const nextProposal = [...currentProposal, proposalItem];
    localStorage.setItem('phant_current_proposal', JSON.stringify(nextProposal));
    setProposalCount(nextProposal.length);

    // Agora o usuário permanece na página, apenas limpamos o estado de "adicionando"
    setTimeout(() => {
      setAddingToProposal(null);
    }, 1500);
  };

  if (module.type === 'admin') return <AdminSettings />;
  if (module.type === 'dashboard') return <SalesDashboard />;
  if (module.type === 'fichario') return <Fichario currentRole={currentRole} />;
  if (module.type === 'calculator') return <ProposalSimulator />;

  if (module.id === 'cultura') return <NossaEssencia currentRole={currentRole} />;
  if (module.id === 'playbook_guia') return <PlaybookGuide />;
  if (module.id === 'sla_metas') return <SLAPage />;

  return (
    <div className="max-w-full mx-auto space-y-12 pb-24 px-4 select-none animate-in fade-in duration-700 relative">
      <header className="space-y-10">
        <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-6">
          <div>
            <h1 className="text-6xl font-black text-gray-900 tracking-tighter leading-none mb-4">Minhas Soluções</h1>
            <p className="text-gray-400 text-xl font-medium tracking-tight">Catálogo Estratégico PhantLab</p>
          </div>
          {isLoading && (
            <div className="flex items-center space-x-2 bg-blue-50 px-4 py-2 rounded-full border border-blue-100">
              <span className="w-2 h-2 rounded-full bg-blue-500 animate-pulse"></span>
              <span className="text-[10px] font-black text-blue-600 uppercase tracking-widest">Sincronizando Base Cloud</span>
            </div>
          )}
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-6 pt-10">
           <div className="bg-white border-l-4 border-[#00B884] p-8 rounded-[32px] shadow-sm hover:shadow-xl transition-all duration-500">
              <div className="flex items-center space-x-3 mb-4">
                 <div className="w-8 h-8 rounded-xl bg-[#00B884]/10 flex items-center justify-center text-[#00B884] font-black text-xs">01</div>
                 <h4 className="text-[11px] font-black text-gray-900 uppercase tracking-widest">Metodologia: Direção</h4>
              </div>
              <p className="text-[13px] font-medium text-gray-500 leading-relaxed">
                Focada em **Base e Cultura**. Ideal para empresas que precisam definir o Norte estratégico, alinhar o time e construir fundamentos sólidos de marca.
              </p>
           </div>
           <div className="bg-white border-l-4 border-[#0095FF] p-8 rounded-[32px] shadow-sm hover:shadow-xl transition-all duration-500">
              <div className="flex items-center space-x-3 mb-4">
                 <div className="w-8 h-8 rounded-xl bg-[#0095FF]/10 flex items-center justify-center text-[#0095FF] font-black text-xs">02</div>
                 <h4 className="text-[11px] font-black text-gray-900 uppercase tracking-widest">Metodologia: Propagação</h4>
              </div>
              <p className="text-[13px] font-medium text-gray-500 leading-relaxed">
                Focada em **Crescimento e Alcance**. Projetos para levar a mensagem mais longe, escalar a aquisição de clientes e dominar novos canais de mercado.
              </p>
           </div>
           <div className="bg-white border-l-4 border-[#7C3AED] p-8 rounded-[32px] shadow-sm hover:shadow-xl transition-all duration-500">
              <div className="flex items-center space-x-3 mb-4">
                 <div className="w-8 h-8 rounded-xl bg-[#7C3AED]/10 flex items-center justify-center text-[#7C3AED] font-black text-xs">03</div>
                 <h4 className="text-[11px] font-black text-gray-900 uppercase tracking-widest">Metodologia: Aceleração</h4>
              </div>
              <p className="text-[13px] font-medium text-gray-500 leading-relaxed">
                Focada em **Velocidade e Tecnologia**. Soluções para quem já tem tração e busca otimização agressiva através de sistemas, IA e automação de escala.
              </p>
           </div>
        </div>

        <div className="flex flex-wrap gap-2 pt-6 border-t border-gray-100">
          {['Todos', 'Marca & Cultura', 'Crescimento (Growth)', 'Tecnologia', 'Cursos & Mentorias'].map(sub => (
            <button
              key={sub}
              onClick={() => setActiveSubcategory(sub)}
              className={`px-8 py-4 rounded-2xl text-[10px] font-black uppercase tracking-widest transition-all ${
                activeSubcategory === sub ? 'bg-black text-white shadow-2xl scale-105' : 'bg-white border border-gray-100 text-gray-400 hover:text-black hover:border-black/10'
              }`}
            >
              {sub}
            </button>
          ))}
        </div>
      </header>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-10">
        {processedData.map((item) => {
          const meta = getCategoryMeta(item.categoria);
          const activeLabels = selectedOptions[item.id] || [];
          const currentPrice = (item.valor_base_num || 0) + (item.variaveis_opcionais || []).filter(o => activeLabels.includes(o.label)).reduce((a, c) => a + c.valor, 0);

          return (
            <div key={item.id} className="bg-white rounded-[40px] border border-gray-100 shadow-sm hover:shadow-2xl transition-all duration-700 overflow-hidden flex flex-col h-full group">
              <div className="p-10 flex-1 flex flex-col space-y-8">
                <div className="flex justify-between items-center">
                  <div className={`px-5 py-2 rounded-full ${meta.bg} text-white text-[9px] font-black uppercase tracking-widest shadow-lg shadow-black/5`}>
                    {item.categoria.toUpperCase()}
                  </div>
                  <div className="flex items-center space-x-2 bg-gray-50 px-4 py-2 rounded-xl border border-gray-100">
                    <svg className="w-3 h-3 text-gray-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M12 8v4l3 3m6-3a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
                    <span className="text-[10px] font-black text-gray-500 uppercase tracking-widest">{item.duracao}</span>
                  </div>
                </div>

                <div className="space-y-3">
                  <h3 className="text-3xl font-black text-gray-900 leading-[1.1] tracking-tighter group-hover:text-blue-600 transition-colors">{item.solucao}</h3>
                  <div className="flex items-center space-x-2">
                    <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{item.subcategoria}</span>
                    <span className="w-1 h-1 rounded-full bg-gray-200"></span>
                    <span className={`text-[10px] font-black uppercase tracking-widest ${item.maturidade === 'Advanced' ? 'text-amber-500' : 'text-gray-300'}`}>Nível {item.maturidade}</span>
                  </div>
                </div>

                <p className="text-gray-400 text-[14px] leading-relaxed font-medium line-clamp-3">
                  {item.descricao || item.promessa}
                </p>
              </div>

              <div className="p-10 pt-0 mt-auto border-t border-gray-50 space-y-8">
                <div className="flex justify-between items-end pt-8">
                  <div>
                    <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest block mb-2">Investimento Base</span>
                    <span className="text-4xl font-black text-gray-900 tracking-tighter">
                      {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(currentPrice)}
                    </span>
                  </div>
                </div>
                <div className="grid grid-cols-1 gap-4">
                  <button onClick={() => setSelectedSolution(item)} className="w-full py-5 bg-gray-900 text-white rounded-2xl font-black text-[10px] uppercase tracking-[0.2em] shadow-xl hover:bg-black transition-all">Ver Ficha Técnica</button>
                  <button onClick={() => addToProposal(item)} className={`w-full py-4 rounded-2xl font-black text-[9px] uppercase tracking-widest transition-all ${addingToProposal === item.id ? 'bg-green-600 text-white scale-95' : 'text-gray-400 hover:bg-gray-50'}`}>
                    {addingToProposal === item.id ? '✓ Adicionado' : '+ Escolher Solução'}
                  </button>
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* CARRINHO FLUTUANTE (FAB) */}
      {proposalCount > 0 && (
        <div className="fixed bottom-32 right-8 z-[70] animate-in slide-in-from-bottom-8 duration-500">
           <button 
             onClick={() => onNavigateToModule?.('calculadora')}
             className="flex items-center space-x-4 bg-black text-white px-8 py-5 rounded-[30px] shadow-2xl hover:scale-105 active:scale-95 transition-all group border border-white/10"
           >
              <div className="relative">
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2.5" d="M9 5H7a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2V7a2 2 0 00-2-2h-2M9 5a2 2 0 002 2h2a2 2 0 002-2M9 5a2 2 0 012-2h2a2 2 0 012 2"/></svg>
                <span className="absolute -top-3 -right-3 w-6 h-6 bg-blue-600 text-white rounded-full flex items-center justify-center text-[10px] font-black border-2 border-black animate-in zoom-in duration-300">
                  {proposalCount}
                </span>
              </div>
              <span className="text-[10px] font-black uppercase tracking-widest">Ver Proposta Simulação</span>
           </button>
        </div>
      )}

      {selectedSolution && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-2xl z-[100] flex items-center justify-center p-6 animate-in fade-in zoom-in-95 duration-500">
          <div className="bg-white w-full max-w-4xl rounded-[60px] shadow-2xl overflow-hidden flex flex-col max-h-[90vh] border border-white/20">
            <div className={`h-3 ${getCategoryMeta(selectedSolution.categoria).bg}`}></div>

            <div className="p-12 md:p-20 overflow-y-auto custom-scrollbar flex-1">
              <div className="flex justify-between items-start mb-16">
                <div className="space-y-6">
