                    <span className={`px-4 py-1.5 rounded-full ${getCategoryMeta(selectedSolution.categoria).light} ${getCategoryMeta(selectedSolution.categoria).text} text-[10px] font-black uppercase tracking-widest`}>
                      {selectedSolution.categoria}
