                  <h2 className="text-5xl font-black text-gray-900 tracking-tighter leading-tight">{selectedSolution.solucao}</h2>
                  <p className="text-blue-600 font-black text-[13px] uppercase tracking-[0.3em]">{selectedSolution.promessa}</p>
