  // Auth Form State
  const [authView, setAuthView] = useState<'options' | 'email-login' | 'email-signup'>('options');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [authError, setAuthError] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const retryCountRef = useRef(0);

  // Captura erros de redirecionamento (Query e Hash)
  useEffect(() => {
    const handleUrlParams = () => {
      const searchParams = new URLSearchParams(window.location.search);
      const hashParams = new URLSearchParams(window.location.hash.substring(1));

      const errorCode = searchParams.get('error') || hashParams.get('error');
      const errorDesc = searchParams.get('error_description') || hashParams.get('error_description');

      if (errorCode || errorDesc) {
        console.error("Auth Event:", { errorCode, errorDesc });
        let msg = errorDesc || errorCode || "Erro na autenticação.";
        const currentOrigin = getAppOrigin();

        if (msg.includes('invalid_request')) {
          msg = `CONFIGURAÇÃO NECESSÁRIA: Você precisa adicionar a URL "${currentOrigin}" no seu Google Cloud Console em "URIs de redirecionamento autorizados".`;
        } else if (msg.includes('access_denied')) {
          msg = "O login foi negado. Se o app for 'Interno', use um e-mail corporativo. Se for 'Externo', verifique se seu e-mail está na lista de Test Users.";
        }

        setAuthError(msg);
        window.history.replaceState({}, document.title, window.location.origin);
      }
    };

    handleUrlParams();
    window.addEventListener('hashchange', handleUrlParams);
    return () => window.removeEventListener('hashchange', handleUrlParams);
  }, []);

  const loadUserProfile = useCallback(async (userId: string, userEmail?: string) => {
    try {
      let profile = await AuthService.getProfile(userId);

      // Regra de Soberania: master@phantlab.com.br é sempre MASTER
      if (userEmail?.toLowerCase() === 'master@phantlab.com.br') {
        if (!profile) {
          profile = { 
            id: userId, 
            role: 'MASTER', 
            full_name: 'Master Admin',
            user_metadata: { full_name: 'Master Admin' } 
          };
        } else {
          profile.role = 'MASTER';
        }
      }

      if (profile) {
        setUserProfile(profile);
        setCurrentRole(profile.role as UserRole);
        retryCountRef.current = 0;
        return true;
      }

      if (retryCountRef.current < 5) {
        retryCountRef.current++;
        await new Promise(r => setTimeout(r, 2000));
        return loadUserProfile(userId, userEmail);
      }
      return false;
    } catch (err) {
      return false;
    }
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session?.user) {
        loadUserProfile(session.user.id, session.user.email).finally(() => setLoading(false));
      } else {
        setLoading(false);
      }
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, newSession) => {
      setSession(newSession);
      if (newSession && (event === 'SIGNED_IN' || event === 'INITIAL_SESSION')) {
        setIsProcessing(true);
        await loadUserProfile(newSession.user.id, newSession.user.email);
        setIsProcessing(false);
      } else if (event === 'SIGNED_OUT') {
        setUserProfile(null);
        setCurrentRole('USER');
      }
    });

    return () => subscription.unsubscribe();
  }, [loadUserProfile]);

  const handleEmailLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError(null);
    setIsProcessing(true);
    try {
      await AuthService.signInWithEmail(email, password);
    } catch (err: any) {
      setAuthError(err.message === 'Invalid login credentials' ? 'E-mail ou senha incorretos.' : err.message);
      setIsProcessing(false);
    }
  };

  const handleEmailSignup = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError(null);
    setIsProcessing(true);
    try {
      await AuthService.signUpWithEmail(email, password, fullName);
      alert('Cadastro realizado! Agora você pode fazer login.');
      setAuthView('email-login');
    } catch (err: any) {
      setAuthError(err.message);
    } finally {
      setIsProcessing(false);
    }
  };

  const selectedModule = PLAYBOOK_STRUCTURE.find(m => m.id === selectedModuleId);

  if (loading || (session && !userProfile && isProcessing)) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-gray-50">
        <div className="flex flex-col items-center space-y-6">
          <div className="w-16 h-16 bg-black rounded-[24px] animate-bounce shadow-2xl flex items-center justify-center">
             <div className="w-4 h-4 bg-white rounded-full"></div>
          </div>
          <div className="flex flex-col items-center text-center">
            <span className="text-[11px] font-black text-gray-900 uppercase tracking-[0.4em]">Sincronizando Workspace Phant</span>
            <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mt-2 animate-pulse">
              {session ? 'Validando permissões...' : 'Iniciando sistemas...'}
            </span>
          </div>
        </div>
      </div>
    );
  }

  if (!session) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-gray-50 p-6 overflow-y-auto">
        <div className="max-w-md w-full bg-white p-12 rounded-[60px] shadow-2xl space-y-10 border border-gray-100 text-center animate-in zoom-in-95 duration-500 my-8">
          <div className="w-20 h-20 bg-black rounded-[30px] flex items-center justify-center text-white text-3xl font-black mx-auto shadow-xl">P</div>

          <div className="space-y-4">
            <h1 className="text-4xl font-black text-gray-900 tracking-tighter leading-tight">PhantLab Playbook</h1>
            <p className="text-gray-400 font-medium text-sm leading-relaxed px-4">
              {authView === 'options' ? 'Escolha como deseja acessar sua central de inteligência comercial.' : 
               authView === 'email-login' ? 'Insira suas credenciais corporativas.' : 
               'Crie sua conta para começar a gerir seus ativos.'}
            </p>
          </div>

          {authError && (
            <div className="p-5 bg-red-50 text-red-600 text-[11px] font-bold rounded-[24px] border border-red-100 uppercase tracking-widest leading-relaxed animate-in fade-in slide-in-from-top-2 flex flex-col items-center gap-3">
              <span>⚠️ {authError}</span>
              {authError.includes(getAppOrigin()) && (
                <button 
                  onClick={() => {
                    navigator.clipboard.writeText(getAppOrigin());
                    alert("URL Copiada! Cole no Google Cloud Console.");
                  }}
                  className="bg-red-600 text-white px-4 py-1.5 rounded-full text-[9px] hover:bg-red-700 transition-colors"
                >
                  Copiar URL para o Google
                </button>
              )}
            </div>
          )}

          <div className="space-y-4">
            {authView === 'options' ? (
              <>
                <button 
                  onClick={() => { setAuthError(null); AuthService.signInWithGoogle(); }}
                  className="w-full py-6 bg-white border border-gray-200 text-gray-900 rounded-[30px] font-black text-xs uppercase tracking-[0.2em] shadow-sm hover:bg-gray-50 hover:shadow-lg transition-all flex items-center justify-center gap-3 group"
                >
                  <svg className="w-5 h-5 group-hover:scale-110 transition-transform" viewBox="0 0 24 24" fill="currentColor">
                    <path d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" fill="#4285F4"/>
                    <path d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" fill="#34A853"/>
                    <path d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" fill="#FBBC05"/>
                    <path d="M12 5.38c1.62 0 3.06.56 4.21 1.66l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" fill="#EA4335"/>
                  </svg>
                  Google Login
                </button>
                <div className="flex items-center gap-4 py-2">
                  <div className="flex-1 h-px bg-gray-100"></div>
                  <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest">Ou</span>
                  <div className="flex-1 h-px bg-gray-100"></div>
                </div>
                <button 
                  onClick={() => setAuthView('email-login')}
                  className="w-full py-6 bg-black text-white rounded-[30px] font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-gray-800 transition-all flex items-center justify-center gap-3"
                >
                  Entrar com E-mail
                </button>
              </>
            ) : (
              <form onSubmit={authView === 'email-login' ? handleEmailLogin : handleEmailSignup} className="space-y-4 text-left">
                {authView === 'email-signup' && (
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-4">Nome Completo</label>
                    <input 
                      type="text" 
                      required 
                      value={fullName}
                      onChange={(e) => setFullName(e.target.value)}
                      className="w-full px-6 py-4 bg-gray-50 border border-transparent rounded-2xl font-bold text-sm focus:bg-white focus:border-black/5 outline-none transition-all"
                      placeholder="Como deseja ser chamado?"
                    />
                  </div>
                )}
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-4">E-mail</label>
                  <input 
                    type="email" 
                    required 
                    value={email}
                    onChange={(e) => setEmail(e.target.value)}
                    className="w-full px-6 py-4 bg-gray-50 border border-transparent rounded-2xl font-bold text-sm focus:bg-white focus:border-black/5 outline-none transition-all"
                    placeholder="seu@email.com"
                  />
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-4">Senha</label>
                  <input 
                    type="password" 
                    required 
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    className="w-full px-6 py-4 bg-gray-50 border border-transparent rounded-2xl font-bold text-sm focus:bg-white focus:border-black/5 outline-none transition-all"
                    placeholder="••••••••"
                  />
                </div>
                <button 
                  type="submit"
                  disabled={isProcessing}
                  className="w-full py-6 bg-black text-white rounded-[30px] font-black text-xs uppercase tracking-[0.2em] shadow-xl hover:bg-gray-800 disabled:opacity-50 transition-all mt-6"
                >
                  {isProcessing ? 'Autenticando...' : authView === 'email-login' ? 'Entrar Agora' : 'Criar Conta'}
                </button>
                <button 
                  type="button"
                  onClick={() => { setAuthView('options'); setAuthError(null); }}
                  className="w-full py-4 text-[10px] font-black text-gray-400 uppercase tracking-widest hover:text-black transition-colors"
                >
                  Voltar para opções
                </button>
              </form>
            )}
          </div>

          <div className="pt-6">
            <p className="text-[11px] font-bold text-gray-400">
              {authView === 'email-signup' ? 'Já possui conta?' : 'Novo por aqui?'}
              <button 
                onClick={() => setAuthView(authView === 'email-signup' ? 'email-login' : 'email-signup')}
                className="ml-2 text-blue-600 font-black hover:underline"
              >
                {authView === 'email-signup' ? 'Fazer Login' : 'Cadastre-se'}
              </button>
            </p>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="flex h-screen bg-gray-50 overflow-hidden font-sans selection:bg-blue-100 selection:text-blue-900">
      <Sidebar 
        modules={PLAYBOOK_STRUCTURE} 
        selectedModuleId={selectedModuleId} 
        onSelectModule={setSelectedModuleId}
        currentRole={currentRole}
        user={{ ...session.user, profile: userProfile }}
      />
      <main className="flex-1 overflow-y-auto relative custom-scrollbar">
        <div className="p-8 md:p-16 max-w-[1600px] mx-auto">
          {selectedModule ? (
            <PlaybookEditor 
              module={selectedModule} 
              currentRole={currentRole} 
              onNavigateToModule={setSelectedModuleId}
            />
          ) : (
            <div className="h-full flex items-center justify-center text-gray-300 font-black uppercase tracking-[0.3em]">
              Módulo não encontrado
            </div>
          )}
        </div>
      </main>
      <AIAssistant currentRole={currentRole} />

      {userProfile?.role === 'MASTER' && (
        <div className="fixed bottom-6 left-6 flex items-center space-x-1 bg-white/90 backdrop-blur-xl p-1.5 rounded-2xl border border-gray-100 shadow-2xl z-[70]">
          {(['MASTER', 'USER'] as UserRole[]).map(role => (
            <button 
              key={role}
              onClick={() => setCurrentRole(role)}
              className={`px-4 py-2 rounded-xl text-[9px] font-black uppercase tracking-widest transition-all ${currentRole === role ? 'bg-black text-white shadow-lg' : 'text-gray-400 hover:text-black hover:bg-gray-100'}`}
            >
              {role}
            </button>
          ))}
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { SupabaseService } from '../services/api';
import { UserRole } from '../types';

interface NossaEssenciaProps {
  currentRole?: UserRole;
}

const DEFAULT_DATA = {
