export const getAppOrigin = () => {
  // Retorna o origin limpo sem barra final
  const origin = window.location.origin;
  return origin.endsWith('/') ? origin.slice(0, -1) : origin;
};

export const supabase = createClient(SUPABASE_URL, SUPABASE_ANON_KEY, {
  auth: {
    autoRefreshToken: true,
    persistSession: true,
    detectSessionInUrl: true,
    flowType: 'pkce' 
  }
});

export const AuthService = {
  async signInWithGoogle() {
    // Usamos o origin absoluto para garantir compatibilidade com Google Cloud
    const redirectTo = `${getAppOrigin()}/`;

    const { error } = await supabase.auth.signInWithOAuth({
      provider: 'google',
      options: {
        redirectTo,
        scopes: 'openid email profile https://www.googleapis.com/auth/calendar.readonly https://www.googleapis.com/auth/drive.file https://www.googleapis.com/auth/drive.metadata.readonly',
        queryParams: {
          access_type: 'offline',
          prompt: 'consent',
        },
      }
    });
    if (error) throw error;
  },

  async signInWithEmail(email: string, password: string) {
    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });
    if (error) throw error;
    return data;
  },

  async signUpWithEmail(email: string, password: string, fullName: string) {
    const isMaster = email.toLowerCase() === ADMIN_EMAIL;
    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        data: {
          full_name: fullName,
          role: (isMaster ? 'MASTER' : 'USER') as UserRole
        }
      }
    });
    if (error) throw error;
    return data;
  },

  async getProfile(userId: string) {
    try {
      const { data, error } = await supabase
        .from('profiles')
        .select('*')
        .eq('id', userId)
        .single();

      if (error) return null;
      return data;
    } catch (err) {
      return null;
    }
  },

  async signOut() {
    try {
      await supabase.auth.signOut();
    } catch (e) {
      console.warn("Erro ao comunicar logout:", e);
    } finally {
      localStorage.clear();
      sessionStorage.clear();
      // Redireciona para a raiz sem parâmetros de hash ou query
      window.location.replace(window.location.origin);
    }
  },

  async getUser() {
    const { data: { user } } = await supabase.auth.getUser();
    return user;
  }
};

export const GoogleApiService = {
  async getAccessToken() {
    const { data: { session } } = await supabase.auth.getSession();
    return session?.provider_token;
  },

  async fetchCalendarEvents() {
    const token = await this.getAccessToken();
    if (!token) return [];

    try {
      const now = new Date().toISOString();
      const endOfDay = new Date();
      endOfDay.setHours(23, 59, 59, 999);

      const response = await fetch(
        `https://www.googleapis.com/calendar/v3/calendars/primary/events?timeMin=${now}&timeMax=${endOfDay.toISOString()}&singleEvents=true&orderBy=startTime`,
        { headers: { Authorization: `Bearer ${token}` } }
      );

      const data = await response.json();
      return data.items || [];
    } catch (error) {
      console.error("Erro ao buscar agenda:", error);
      return [];
    }
  },

  async uploadToDrive(fileName: string, content: string) {
    const token = await this.getAccessToken();
    if (!token) throw new Error("Não autenticado com Google");

    const metadata = {
      name: fileName,
      mimeType: 'text/plain',
    };

    const form = new FormData();
    form.append('metadata', new Blob([JSON.stringify(metadata)], { type: 'application/json' }));
    form.append('file', new Blob([content], { type: 'text/plain' }));

    const response = await fetch('https://www.googleapis.com/upload/drive/v3/files?uploadType=multipart', {
      method: 'POST',
      headers: { Authorization: `Bearer ${token}` },
      body: form
    });

    if (!response.ok) throw new Error("Falha no upload");
    return await response.json();
  }
};

export const SupabaseService = {
  async fetchSolutions(): Promise<SolutionItem[]> {
    try {
      const { data, error } = await supabase.from('solutions').select('*').order('id', { ascending: true });
      if (error) throw error;
      return (data || []).map(item => ({
        ...item,
        id: String(item.id), 
        variaveis_opcionais: Array.isArray(item.variaveis_opcionais) ? item.variaveis_opcionais : []
      }));
    } catch (err: any) {
      console.error('Erro ao buscar soluções:', err.message);
      return [];
    }
  },

  async syncSolutions(solutions: SolutionItem[]) {
    try {
      const payload = solutions.map(s => ({
        id: String(s.id),
        solucao: s.solucao,
        promessa: s.promessa,
        descricao: s.descricao,
        categoria: s.categoria,
        subcategoria: s.subcategoria,
        duracao: s.duracao,
        maturidade: s.maturidade,
        valor_base_num: s.valor_base_num,
        variaveis_opcionais: s.variaveis_opcionais
      }));
      const { error } = await supabase.from('solutions').upsert(payload, { onConflict: 'id' });
      if (error) throw error;
      return { success: true };
    } catch (err: any) {
      return { success: false, message: err.message };
    }
  },

  async fetchEssencia() {
    try {
      const { data, error } = await supabase.from('essencia_config').select('content').eq('id', 'main').single();
      if (error) return null;
      return data.content;
    } catch {
      return null;
    }
  },

  async syncEssencia(content: any) {
    try {
      const { error } = await supabase.from('essencia_config').upsert({ id: 'main', content }, { onConflict: 'id' });
      if (error) throw error;
      return { success: true };
    } catch (err: any) {
      return { success: false, message: err.message };
    }
  },

  async fetchAIConfig(): Promise<AIConfig | null> {
    try {
      const { data, error } = await supabase.from('ai_config').select('content').eq('id', 'mentor').single();
      if (error) return null;
      return data.content;
    } catch {
      return null;
    }
  },

  async syncAIConfig(content: AIConfig) {
    try {
      const { error } = await supabase.from('ai_config').upsert({ id: 'mentor', content }, { onConflict: 'id' });
      if (error) throw error;
      return { success: true };
    } catch {
      return { success: false };
    }
  },

  async fetchFicharioFromDb() {
    try {
      const { data, error } = await supabase.from('fichario').select('*').order('nome', { ascending: true });
      if (error) return [];
      return data || [];
    } catch {
      return [];
    }
  },

  async syncFicharioToDb(files: any[]) {
    if (files.length === 0) return;
    try {
      const payload = files.map(file => ({
        drive_file_id: file.id,
        nome: file.name,
        formato: file.type,
        link: file.url,
