export const StorageService = {
  async saveDriveConfig(link: string) {
    localStorage.setItem('phant_drive_folder_link', link);
    window.dispatchEvent(new Event('storage'));
    return { success: true };
  },

  async getSavedDriveConfig() {
    return localStorage.getItem('phant_drive_folder_link') || `https://drive.google.com/drive/folders/${DEFAULT_DRIVE_FOLDER_ID}`;
  },

  async fetchDriveFiles(inputLink: string) {
    const folderId = this.extractFolderId(inputLink);
    const finalUrl = `${PROXY_URL}?id=${folderId}&_t=${Date.now()}`;
    try {
      const response = await fetch(finalUrl);
      if (!response.ok) throw new Error(`HTTP_ERROR_${response.status}`);
      const data = await response.json();
      return this.processFiles(data.files || data.items || [], folderId);
    } catch (err: any) {
      throw new Error("BLOCK_BY_BROWSER");
    }
  },

  processFiles(files: any[], folderId: string) {
    return files.map((file: any) => {
      const fileId = file.id || file.fileId;
      const modTime = file.modifiedTime || null;
      return {
        id: fileId,
        name: file.name || file.title || "Arquivo sem nome",
        type: this.mapMimeToType(file.mimeType || ""),
        size: file.size ? this.formatBytes(parseInt(file.size)) : '---',
        updatedAt: modTime ? new Date(modTime).toLocaleDateString('pt-BR') : '---',
        rawUpdatedAt: modTime,
        url: `https://drive.google.com/file/d/${fileId}/view`,
        previewUrl: `https://drive.google.com/file/d/${fileId}/preview`,
        downloadUrl: `https://drive.google.com/uc?export=download&id=${fileId}`,
        thumbnail: `https://drive.google.com/thumbnail?id=${fileId}&sz=w400`,
        folderId: folderId,
        raw: file 
      };
    });
  },

  extractFolderId(url: string) {
    const match = url.match(/(?:folders\/|id=)([-\w]{25,})/);
    return match ? match[1] : DEFAULT_DRIVE_FOLDER_ID;
  },

  mapMimeToType(mimeType: string) {
    const mime = (mimeType || '').toLowerCase();
    if (mime === 'application/pdf') return 'pdf';
    if (mime === 'application/vnd.google-apps.document') return 'gdoc';
    if (mime === 'application/vnd.google-apps.spreadsheet') return 'gsheet';
    if (mime === 'application/vnd.google-apps.presentation') return 'gslides';
    if (mime.includes('video/')) return 'video';
    if (mime.includes('image/')) return 'image';
    return 'unknown';
  },

  formatBytes(bytes: number) {
    if (!bytes || isNaN(bytes)) return '---';
    const i = Math.floor(Math.log(bytes) / Math.log(1024));
    const sizes = ['B', 'KB', 'MB', 'GB'];
    return (bytes / Math.pow(1024, i)).toFixed(1) + ' ' + sizes[i];
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import Sidebar from './components/Sidebar';
import PlaybookEditor from './components/PlaybookEditor';
import AIAssistant from './components/AIAssistant';
import { PLAYBOOK_STRUCTURE } from './constants';
import { UserRole } from './types';
import { AuthService, supabase, getAppOrigin } from './services/api';

const App: React.FC = () => {
  const [session, setSession] = useState<any>(null);
  const [userProfile, setUserProfile] = useState<any>(null);
  const [selectedModuleId, setSelectedModuleId] = useState<string | null>('dashboard');
  const [currentRole, setCurrentRole] = useState<UserRole>('USER');
  const [loading, setLoading] = useState(true);

  // Auth Form State
  const [authView, setAuthView] = useState<'options' | 'email-login' | 'email-signup'>('options');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [fullName, setFullName] = useState('');
  const [authError, setAuthError] = useState<string | null>(null);
  const [isProcessing, setIsProcessing] = useState(false);

  const retryCountRef = useRef(0);

  // Captura erros de redirecionamento (Query e Hash)
  useEffect(() => {
    const handleUrlParams = () => {
      const searchParams = new URLSearchParams(window.location.search);
      const hashParams = new URLSearchParams(window.location.hash.substring(1));

      const errorCode = searchParams.get('error') || hashParams.get('error');
      const errorDesc = (searchParams.get('error_description') || hashParams.get('error_description') || "").toLowerCase();

      if (errorCode || errorDesc) {
        let msg = errorDesc || errorCode || "Erro na autenticação.";

        if (errorDesc.includes('access_denied') || errorCode === '403') {
          msg = "ERRO 403: ACESSO NEGADO. Isso ocorre quando o e-mail não tem permissão no console do Google. Adicione seu e-mail como 'Test User' ou mude o app para Produção.";
        } else if (errorDesc.includes('invalid_request')) {
          msg = `CONFIGURAÇÃO NECESSÁRIA: Adicione a URL "${getAppOrigin()}/" nos URIs de Redirecionamento Autorizados do seu Google Cloud.`;
        }

        setAuthError(msg);
        window.history.replaceState({}, document.title, window.location.origin);
      }
    };

    handleUrlParams();
    window.addEventListener('hashchange', handleUrlParams);
    return () => window.removeEventListener('hashchange', handleUrlParams);
  }, []);

  const loadUserProfile = useCallback(async (userId: string, userEmail?: string) => {
    try {
      let profile = await AuthService.getProfile(userId);

      if (userEmail?.toLowerCase() === 'master@phantlab.com.br') {
        if (!profile) {
          profile = { 
            id: userId, 
            role: 'MASTER', 
            full_name: 'Master Admin',
            user_metadata: { full_name: 'Master Admin' } 
          };
        } else {
          profile.role = 'MASTER';
        }
      }

      if (profile) {
        setUserProfile(profile);
        setCurrentRole(profile.role as UserRole);
        retryCountRef.current = 0;
        return true;
      }

      if (retryCountRef.current < 3) {
        retryCountRef.current++;
        await new Promise(r => setTimeout(r, 1000));
        return loadUserProfile(userId, userEmail);
      }
      return false;
    } catch (err) {
      return false;
    }
  }, []);

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      setSession(session);
      if (session?.user) {
        loadUserProfile(session.user.id, session.user.email).finally(() => setLoading(false));
      } else {
        setLoading(false);
      }
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange(async (event, newSession) => {
      if (newSession && (event === 'SIGNED_IN' || event === 'INITIAL_SESSION')) {
        setSession(newSession);
        setIsProcessing(true);
        await loadUserProfile(newSession.user.id, newSession.user.email);
        setIsProcessing(false);
      } else if (event === 'SIGNED_OUT') {
        setSession(null);
        setUserProfile(null);
        setCurrentRole('USER');
      }
    });

    return () => subscription.unsubscribe();
  }, [loadUserProfile]);

  const handleEmailLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError(null);
    setIsProcessing(true);
    try {
      await AuthService.signInWithEmail(email, password);
    } catch (err: any) {
      setAuthError(err.message === 'Invalid login credentials' ? 'E-mail ou senha incorretos.' : err.message);
      setIsProcessing(false);
    }
  };

  const handleEmailSignup = async (e: React.FormEvent) => {
    e.preventDefault();
    setAuthError(null);
    setIsProcessing(true);
    try {
      await AuthService.signUpWithEmail(email, password, fullName);
      alert('Cadastro realizado! Agora você pode fazer login.');
      setAuthView('email-login');
    } catch (err: any) {
      setAuthError(err.message);
    } finally {
      setIsProcessing(false);
    }
  };

  const copyRedirectUri = () => {
    const uri = `${getAppOrigin()}/`;
    navigator.clipboard.writeText(uri);
    alert("URL Copiada: " + uri);
  };

  if (loading || (session && !userProfile && isProcessing)) {
    return (
      <div className="h-screen w-full flex items-center justify-center bg-gray-50">
        <div className="flex flex-col items-center space-y-6">
          <div className="w-16 h-16 bg-black rounded-[24px] animate-bounce shadow-2xl flex items-center justify-center">
             <div className="w-4 h-4 bg-white rounded-full"></div>
          </div>
          <div className="flex flex-col items-center text-center">
            <span className="text-[11px] font-black text-gray-900 uppercase tracking-[0.4em]">PhantLab OS Sincronizando</span>
            <span className="text-[9px] font-bold text-gray-400 uppercase tracking-widest mt-2 animate-pulse">
              {session ? 'Validando permissões de acesso...' : 'Iniciando sistemas seguros...'}
            </span>
          </div>
        </div>
      </div>
    );
  }

